import React from 'react';
import TaskItem from './TaskItem';

export default function TaskList({ tasks, role, demoQuota, activeTaskId, showToast, simulateExecution, setDemoQuota }) {
  return (
    <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
      <h3 className="text-lg font-bold text-slate-800 mb-4">Nhiệm vụ của tôi / Đội nhóm</h3>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse font-sans text-sm">
          <thead>
            <tr className="border-b border-slate-100 text-slate-400 text-xs font-bold uppercase">
              <th className="pb-3">Hệ sinh thái</th>
              <th className="pb-3">Worker</th>
              <th className="pb-3">Người chạy</th>
              <th className="pb-3">Trạng thái</th>
              <th className="pb-3 text-right">Hành động</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {tasks.map(task => (
              <TaskItem 
                key={task.id}
                task={task}
                role={role}
                demoQuota={demoQuota}
                activeTaskId={activeTaskId}
                showToast={showToast}
                simulateExecution={simulateExecution}
                setDemoQuota={setDemoQuota}
              />
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
