const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// Hàm gọi Gemini API phục vụ các tính năng AI
const callGeminiAPI = async (prompt, systemPrompt = "", useSearch = false) => {
  const apiKey = process.env.REACT_APP_GEMINI_API_KEY || "";
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${apiKey}`;
  
  const payload = {
    contents: [{ parts: [{ text: prompt }] }],
    ...(systemPrompt && { systemInstruction: { parts: [{ text: systemPrompt }] } }),
    ...(useSearch && { tools: [{ "google_search": {} }] })
  };

  let delay = 1000;
  for (let i = 0; i < 5; i++) {
    try {
      const response = await axios.post(url, payload);
      const candidate = response.data?.candidates?.[0];
      const text = candidate?.content?.parts?.[0]?.text;
      
      let sources = [];
      const groundingMetadata = candidate?.groundingMetadata;
      if (groundingMetadata && groundingMetadata.groundingAttributions) {
        sources = groundingMetadata.groundingAttributions
          .map(attr => ({
            uri: attr.web?.uri,
            title: attr.web?.title,
          }))
          .filter(source => source.uri && source.title);
      }

      if (text) return { text, sources };
      throw new Error("Phản hồi rỗng từ API");
    } catch (error) {
      if (i === 4) {
        throw new Error("Không thể kết nối với trí tuệ nhân tạo Gemini sau 5 lần thử.");
      }
      await sleep(delay);
      delay *= 2;
    }
  }
};

// Hàm gọi Gemini TTS
const callGeminiTTS = async (textToSpeak, voiceName = "Zephyr") => {
  const apiKey = process.env.REACT_APP_GEMINI_API_KEY || ""; 
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-tts:generateContent?key=${apiKey}`;

  const payload = {
    contents: [{
      parts: [{ text: `Say clearly and professional: ${textToSpeak}` }]
    }],
    generationConfig: {
      responseModalities: ["AUDIO"],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voiceName }
        }
      }
    }
  };

  let delay = 1000;
  for (let i = 0; i < 5; i++) {
    try {
      const response = await axios.post(url, payload);
      const part = response.data?.candidates?.[0]?.content?.parts?.[0];
      const audioData = part?.inlineData?.data;
      const mimeType = part?.inlineData?.mimeType;

      if (audioData && mimeType) {
        let sampleRate = 24000;
        const rateMatch = mimeType.match(/rate=(\d+)/);
        if (rateMatch) {
          sampleRate = parseInt(rateMatch[1], 10);
        }
        return { audioData, sampleRate };
      }
      throw new Error("Không thể tổng hợp giọng nói từ API");
    } catch (error) {
      if (i === 4) throw error;
      await sleep(delay);
      delay *= 2;
    }
  }
};

const base64ToArrayBuffer = (base64) => {
  const binaryString = window.atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
};

const pcmToWav = (pcm16Data, sampleRate) => {
  const buffer = new ArrayBuffer(44 + pcm16Data.byteLength);
  const view = new DataView(buffer);
  
  view.setUint32(0, 0x46464952, true); // "RIFF"
  view.setUint32(4, 36 + pcm16Data.byteLength, true); // File size
  view.setUint32(8, 0x45564157, true); // "WAVE"
  
  view.setUint32(12, 0x20746d66, true); // "fmt "
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true); // Raw PCM
  view.setUint16(22, 1, true); // Mono Channel
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true); // 16-bit
  
  view.setUint32(36, 0x61746164, true); // "data"
  view.setUint32(40, pcm16Data.byteLength, true);
  
  const pcmBytes = new Uint8Array(pcm16Data);
  for (let i = 0; i < pcmBytes.length; i++) {
    view.setUint8(44 + i, pcmBytes[i]);
  }
  
  return new Blob([view], { type: 'audio/wav' });
};

