    setActiveTaskId(taskId);
    setWsLogs(prev => [...prev, `[System] Gửi tín hiệu ưu tiên cao (high-priority) tới Engine...`]);
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: 'RUNNING', priority: 'high' } : t));

