/* Manager: Đề Xuất Worker Mới & Code Scaffolder */
const ManagerSuggestPanel = ({ showToast }) => {
  const [workerName, setWorkerName] = useState('');
  const [description, setDescription] = useState('');
  const [scaffoldCode, setScaffoldCode] = useState('');
  const [loadingCode, setLoadingCode] = useState(false);

  const handleSuggest = (e) => {
    e.preventDefault();
    showToast('Gửi đề xuất Worker thành công!');
    setWorkerName('');
    setDescription('');
  };

  const handleGenerateScaffoldWithAI = async () => {
    if (!workerName || !description) return;
    setLoadingCode(true);
    const systemPrompt = "Bạn là Kỹ sư phần mềm Python chuyên nghiệp chuyên thiết kế cấu trúc Modular Worker cho các hệ thống Automation Orchestrator.";
    try {
      const response = await callGeminiAPI(`Hãy sinh mã nguồn Python Worker có tên ${workerName} với mục tiêu: ${description}`, systemPrompt);
      setScaffoldCode(response.text);
      showToast('Tạo code mẫu bằng AI thành công!');
    } catch (e) {
      setScaffoldCode('Lỗi trong quá trình kết xuất mã nguồn.');
    } finally {
      setLoadingCode(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 max-w-6xl">
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
        <h3 className="text-lg font-bold text-slate-800">💡 Đề Xuất Worker Mới (Manager Panel)</h3>
        <form onSubmit={handleSuggest} className="space-y-4">
          <div>
            <label className="block text-xs font-semibold text-slate-500 mb-1">Tên Worker đề xuất</label>
            <input 
              type="text" 
              required
              className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
              value={workerName}
              onChange={(e) => setWorkerName(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-500 mb-1">Mô tả nghiệp vụ</label>
            <textarea 
              rows="4"
              required
              className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            <button 
              type="button" 
              onClick={handleGenerateScaffoldWithAI}
              className="flex-1 bg-violet-600 hover:bg-violet-700 text-white font-bold py-2.5 rounded-lg text-sm transition"
            >
              {loadingCode ? 'Đang soạn code...' : '✨ Tự sinh code Python'}
            </button>
            <button type="submit" className="bg-emerald-600 hover:bg-emerald-700 text-white font-bold px-5 py-2.5 rounded-lg text-sm transition">
              Gửi đề xuất
            </button>
          </div>
        </form>
      </div>

      <div className="bg-slate-900 text-slate-100 p-6 rounded-xl border border-slate-800 flex flex-col">
        <h4 className="text-xs font-bold text-slate-400 uppercase mb-3">✨ Python Worker Scaffold (Gemini Code)</h4>
        <div className="flex-1 overflow-auto bg-slate-950 p-4 rounded-lg border border-slate-800 font-mono text-xs text-blue-300 whitespace-pre-wrap leading-relaxed">
          {scaffoldCode || '# Nhấn nút "Tự sinh code Python" để xuất mã nguồn mẫu theo chuẩn của SEN V3.'}
        </div>
      </div>
    </div>
  );
};

/* Trợ lý AI Copilot */
const AIAssistantPanel = ({ showToast, wsLogs }) => {
  const [messages, setMessages] = useState([
    { role: 'assistant', text: 'Xin chào! Tôi là Trợ lý SEN V3 AI Copilot. Tôi có thể hỗ trợ bạn thiết lập worker, chẩn đoán logs hoặc tìm kiếm các tài liệu DevOps mới nhất.', sources: [] }
  ]);
  const [input, setInput] = useState('');
  const [useSearch, setUseSearch] = useState(false);
  const [loading, setLoading] = useState(false);

  const [selectedVoice, setSelectedVoice] = useState('Zephyr');
  const [activeSpeechIndex, setActiveSpeechIndex] = useState(null);
  const audioRef = useRef(null);

  const handleSendMessage = async (e) => {
    e.preventDefault();
    if (!input.trim() || loading) return;

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage, sources: [] }]);
    setLoading(true);

    const systemPrompt = "Bạn là kiến trúc sư hệ thống và chuyên viên DevOps có trình độ cao của hệ sinh thái SEN V3. Bạn hãy trả lời cực kỳ chi tiết, mạch lạc, dễ hiểu bằng tiếng Việt.";

    try {
      const response = await callGeminiAPI(userMessage, systemPrompt, useSearch);
      setMessages(prev => [...prev, { role: 'assistant', text: response.text, sources: response.sources }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'assistant', text: `❌ Lỗi: ${err.message}`, sources: [] }]);
    } finally {
      setLoading(false);
    }
  };

  const speakMessage = async (text, index) => {
    try {
      if (activeSpeechIndex === index) {
        if (audioRef.current) audioRef.current.pause();
        setActiveSpeechIndex(null);
        return;
      }

      setActiveSpeechIndex(index);
      const sanitizedText = text.replace(/[#*`_\-\n]/g, ' ');
      const { audioData, sampleRate } = await callGeminiTTS(sanitizedText, selectedVoice);

      const pcmBuffer = base64ToArrayBuffer(audioData);
      const wavBlob = pcmToWav(pcmBuffer, sampleRate);
      const audioUrl = URL.createObjectURL(wavBlob);

      if (audioRef.current) {
        audioRef.current.src = audioUrl;
        audioRef.current.play();
      }
    } catch (err) {
      showToast(`Không thể phát giọng nói: ${err.message}`, "error");
      setActiveSpeechIndex(null);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 max-w-6xl">
      <div className="lg:col-span-2 bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col h-[500px]">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-900 text-white rounded-t-xl">
          <div>
            <h3 className="font-bold text-sm">🤖 SEN V3 AI Copilot</h3>
            <p className="text-xs text-slate-400">Được tối ưu hóa bằng Gemini API</p>
          </div>
          <label className="flex items-center gap-2 text-xs cursor-pointer">
            <input 
              type="checkbox" 
              className="rounded text-violet-600 focus:ring-violet-500"
              checked={useSearch}
              onChange={(e) => setUseSearch(e.target.checked)}
            />
            <span className={useSearch ? "text-violet-400 font-bold" : "text-slate-400"}>
              🔍 Google Search
            </span>
          </label>
        </div>

        <div className="flex-1 p-4 overflow-y-auto space-y-3 bg-slate-50">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`max-w-[85%] rounded-lg p-3 text-sm shadow-sm relative ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : 'bg-white border border-slate-200 text-slate-800 rounded-bl-none'
              }`}>
                <div className="whitespace-pre-wrap leading-relaxed">{msg.text}</div>
                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-3 pt-2 border-t border-slate-100 text-xs text-slate-400">
                    <div className="font-semibold mb-1 text-slate-500">📌 Nguồn trích dẫn:</div>
                    <div className="flex flex-wrap gap-1.5">
                      {msg.sources.map((src, sIdx) => (
                        <a 
                          key={sIdx} 
                          href={src.uri} 
                          target="_blank" 
                          rel="noreferrer" 
                          className="bg-slate-100 text-slate-600 border border-slate-200 px-2 py-0.5 rounded hover:bg-slate-200 transition truncate max-w-[150px]"
                          title={src.title}
                        >
                          🌐 {src.title}
                        </a>
                      ))}
                    </div>
                  </div>
                )}
                {msg.role === 'assistant' && (
                  <button onClick={() => speakMessage(msg.text, idx)} className="absolute bottom-1 right-1 opacity-40 hover:opacity-100 p-1">
                    🔊
                  </button>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="text-xs text-slate-400 italic">Gemini đang phản hồi...</div>
          )}
        </div>

        <form onSubmit={handleSendMessage} className="p-3 border-t border-slate-100 flex gap-2">
          <input 
            type="text" 
            className="flex-1 px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none"
            placeholder="Hỏi bất kỳ điều gì về hệ thống..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button type="submit" className="bg-violet-600 hover:bg-violet-700 text-white px-4 py-2 rounded-lg text-xs font-bold transition shadow-sm">
            Gửi
          </button>
        </form>
      </div>

      {/* Voice Synthesizer Selection */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
        <div>
          <h3 className="text-base font-bold text-slate-800 mb-1">🎙️ Gemini Speech Service</h3>
          <p className="text-xs text-slate-400">Cấu hình giọng nói TTS chất lượng cao</p>
        </div>
        <div className="grid grid-cols-2 gap-2">
          {['Zephyr', 'Kore', 'Fenrir', 'Puck'].map(v => (
            <button 
              key={v} 
              onClick={() => setSelectedVoice(v)}
              className={`py-2 text-xs font-bold rounded-lg border transition ${
                selectedVoice === v ? 'bg-violet-50 border-violet-500 text-violet-700' : 'bg-white border-slate-200 hover:bg-slate-50'
              }`}
            >
              👤 {v}
            </button>
          ))}
        </div>
        <audio ref={audioRef} onEnded={() => setActiveSpeechIndex(null)} onError={() => setActiveSpeechIndex(null)} className="hidden" />
      </div>
    </div>
  );
};

export default App;
